import{_ as l,o as t,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"F07: 存貨週轉效率同業對比 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260511/F07_存貨週轉效率同業對比.md","filePath":"審計報告庫/財務審計/6261_久元/20260511/F07_存貨週轉效率同業對比.md"}'),o={name:"審計報告庫/財務審計/6261_久元/20260511/F07_存貨週轉效率同業對比.md"};function e(n,a,s,h,d,u){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="f07-存貨週轉效率同業對比-財務審計專家報告" tabindex="-1">F07: 存貨週轉效率同業對比 - 財務審計專家報告 <a class="header-anchor" href="#f07-存貨週轉效率同業對比-財務審計專家報告" aria-label="Permalink to &quot;F07: 存貨週轉效率同業對比 - 財務審計專家報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>存貨週轉天數與同業相比是否具備競爭優勢？整體營運週期是否處於擴張狀態？</p></blockquote><h2 id="🎯-專家直斷-75-字" tabindex="-1">🎯 專家直斷（75 字） <a class="header-anchor" href="#🎯-專家直斷-75-字" aria-label="Permalink to &quot;🎯 專家直斷（75 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：久元 DIO 520-728 天為同業最差，對比京元 68 天高出 7-10 倍。現金循環 484 天亦遙遙落後同業，營運資金效率為結構性劣勢。</li></ul><h2 id="📊-診斷評級-136-字" tabindex="-1">📊 診斷評級（136 字） <a class="header-anchor" href="#📊-診斷評級-136-字" aria-label="Permalink to &quot;📊 診斷評級（136 字）&quot;">​</a></h2><ul><li><strong>重點數據</strong>：DIO 久元 520 天 vs 京元 68 天 vs 精測 546 天；DSO 久元 119 天 vs 京元 50 天 vs 精測 52 天；現金循環天數 久元 484 天 vs 京元 48 天 vs 精測 355 天。久元 DIO 較京元高出 665%、較精測雖接近但現金循環仍多 129 天。</li><li><strong>診斷見解</strong>：久元同時經營代工服務與設備製造，存貨週轉必然劣於純測試商。但與同有設備業務的精測相比，久元的 DSO 更差（119 天 vs 52 天），導致現金循環整整多出 129 天（+36%），營運資金效率處於同業末段班。</li></ul><h2 id="🔍-答詢詳解-430-字" tabindex="-1">🔍 答詢詳解（430 字） <a class="header-anchor" href="#🔍-答詢詳解-430-字" aria-label="Permalink to &quot;🔍 答詢詳解（430 字）&quot;">​</a></h2><h3 id="一、同業存貨週轉階差分析" tabindex="-1">一、同業存貨週轉階差分析 <a class="header-anchor" href="#一、同業存貨週轉階差分析" aria-label="Permalink to &quot;一、同業存貨週轉階差分析&quot;">​</a></h3><ul><li><strong>核心重點</strong>：久元 DIO 520 天（2025）對比以下同業： <ul><li><strong>京元電子 2449</strong>（純測試代工）：DIO 68 天。差異根源：京元無設備製造業務，存貨僅為測試耗材與備品，週轉極快。</li><li><strong>精測 6510</strong>（探針卡+測試）：DIO 546 天。精測的探針卡為客製化產品，從接單到交貨需備特殊材料，DIO 高達 546 天，與久元相近。</li></ul></li><li><strong>深度見解</strong>：久元的 DIO 高源於兩大結構性因素：①自有設備製造需備大量原物料（438M/1,169M = 37.5%），從採購到出貨週期長；②代工備料（測試相關耗材）有一定庫存水位。2024 年 DIO 曾飆升至 728 天（存貨 13.8 億歷史高點），2025 年已回落至 520 天，去化進度正面但仍在同業末段。</li></ul><h3 id="二、營運週期與現金循環效率-附-2026-月營收更新" tabindex="-1">二、營運週期與現金循環效率（附 2026 月營收更新） <a class="header-anchor" href="#二、營運週期與現金循環效率-附-2026-月營收更新" aria-label="Permalink to &quot;二、營運週期與現金循環效率（附 2026 月營收更新）&quot;">​</a></h3><ul><li><strong>核心重點</strong>：現金循環天數對比： <ul><li>久元：514 天（2024）→484 天（2025），改善 30 天（-5.8%）</li><li>京元：45→48 天，穩定</li><li>精測：233→355 天，惡化 122 天（+52%）</li></ul></li><li><strong>深度見解</strong>：久元的現金循環改善主要來自 DIO 下降（728→520，-208 天）與 DPO 縮減（300→155 天，-145 天）的連動效應。雖然 DIO 降有助現金回收，但 DPO 縮減意味公司減少對供應商的帳款擠壓，反映付款正常化而非效率提升。真正的效率改善需 DSO 同步下降才具意義。<strong>2026 年 1-4 月營收累計 +6.3%（YoY），Q1 +8.9%，初期動能有利於存貨去化，但 4 月已降溫至 -1.2%，需觀察下半年需求是否持續。</strong></li></ul><h3 id="三、存貨結構與產業定位" tabindex="-1">三、存貨結構與產業定位 <a class="header-anchor" href="#三、存貨結構與產業定位" aria-label="Permalink to &quot;三、存貨結構與產業定位&quot;">​</a></h3><ul><li><strong>核心重點</strong>：久元存貨結構：製成品 46.7%、原物料 37.5%、在製品 15.5%。原物料佔比為三類同業最高。</li><li><strong>深度見解</strong>：高原物料佔比反映久元設備製造需備多種客製化料件，供應鏈管理難度高。若管理層能縮短備料週期（如 JIT 模式），DIO 可望降至 350-400 天（接近精測 2023 年 307 天水準），屆時現金循環可壓縮至 350 天，釋放約 2-3 億營運資金。</li></ul><h2 id="💡-專家評析-282-字" tabindex="-1">💡 專家評析（282 字） <a class="header-anchor" href="#💡-專家評析-282-字" aria-label="Permalink to &quot;💡 專家評析（282 字）&quot;">​</a></h2><ol><li><strong>現金循環為產業最差的結構性劣勢（利空）</strong>：484 天的現金循環意味從付錢買料到收到貨款需 16 個月。雖然部分歸因於設備業務的商業模式，但相較京元電子的 48 天（純測試），久元的營運資金效率低一個數量級。一旦營收動能趨緩，資金鏈壓力將以乘數放大。</li><li><strong>DSO 劣於同業反映收款話語權弱（壓力）</strong>：DSO 119 天遠遜於京元 50 天與精測 52 天。京元為全球前三大測試代工廠，議價能力強（要求客戶 30-60 天付款）。久元的 DSO 落在 86-119 天區間，反映對下游客戶缺乏收款主導權——設備客戶常要求 longer payment terms（60-90 天），代工客戶亦無強制預付。</li><li><strong>設備業務擴張恐持續惡化現金循環（警訊）</strong>：自有產品佔比從 37% 升至 40%、營收成長至 16.9 億。設備業務比重越高，存貨壓力越大。若管理層為追求營收成長而持續擴大設備事業，短期營益率雖有撐（高毛利），但中長期營運資金佔用將持續侵蝕 ROE。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (inventory_check 6261, 2449, 6510)</li><li>原始數據：FinMind TaiwanStockBalanceSheet + TaiwanStockFinancialStatements</li><li>同業對比：京元電子 2449（純測試代工）、精測 6510（探針卡+測試服務）</li><li>查詢參數：stock_id=6261, 2449, 6510; 年度 2023-2025</li><li>數據查詢日期：2026-05-11</li></ul>',19)])])}const g=l(o,[["render",e]]);export{_ as __pageData,g as default};
